INSERT INTO "excel"."${tableName}"(
	 "_annox",
	 "_annoy",


	 	"${column}"


	 ,"_geometry"
) VALUES (
	 ST_X (ST_Centroid (ST_Transform ( ST_GeomFromText ( #{line}, 4326 ), 5186 ))),
	 ST_Y (ST_Centroid (ST_Transform ( ST_GeomFromText ( #{line}, 4326 ), 5186 ))),


	 	#{value}


	 ,ST_Transform ( ST_GeomFromText ( #{line}, 4326 ), 5186 )
);
